def get_hookcallers(self) -> dict[str, object]:
    """Return a mapping of hook names to their HookCaller objects.

    Useful for introspection and debugging of registered hooks.
    """
    return {name: caller for name, caller in vars(self.hook).items() if not name.startswith('_')}

