"""Tests for HookimplMarker."""

import pluggy

hookimpl = pluggy.HookimplMarker('test')


def test_basic_hookimpl():
    @hookimpl
    def my_hook():
        pass

    assert hasattr(my_hook, 'test_impl')


def test_tryfirst_flag():
    @hookimpl(tryfirst=True)
    def my_hook():
        pass

    marker = getattr(my_hook, 'test_impl')
    assert marker.get('tryfirst') is True


def test_wrapper_option():
    @hookimpl(wrapper=True)
    def my_hook():
        pass

    marker = getattr(my_hook, 'test_impl')
    assert marker.get('wrapper') is True
